package src.blocks.forms.org.apache.cocoon.forms.binding;

public class CustomJXPathBinding extends JXPathBindingBase { private final String widgetId ; private final String xpath ; private final AbstractCustomBinding wrappedBinding ; public CustomJXPathBinding ( CommonAttributes commonAtts , String widgetId , String xpath , AbstractCustomBinding wrappedBinding ) { super ( commonAtts ) ; this . widgetId = widgetId ; this . xpath = xpath ; this . wrappedBinding = wrappedBinding ; } public void doLoad ( Widget frmModel , JXPathContext jxpc ) throws BindingException { Widget selectedWidget = selectWidget ( frmModel , this . widgetId ) ; JXPathContext context = jxpc . getRelativeContext ( jxpc . getPointer ( this . xpath ) ) ; this . wrappedBinding . loadFormFromModel ( selectedWidget , context ) ; } public void doSave ( Widget frmModel , JXPathContext jxpc ) throws BindingException { Widget selectedWidget = selectWidget ( frmModel , this . widgetId ) ; JXPathContext context = jxpc . getRelativeContext ( jxpc . getPointer ( this . xpath ) ) ; this . wrappedBinding . saveFormToModel ( selectedWidget , context ) ; } }